import "single_sig.ark";

options {
  server = server;
  exit = exit;
}

contract CappedSynth(
  pubkey  claimPk,
  pubkey  longPk,
  pubkey  oraclePk,
  bytes32 ticker,
  int     entryPrice,
  int     notionalFiat,
  int     totalCollateral,
  int     claimMargin,
  int     fundingRatePerSec,
  int     lastUpdate,
  int     exitFeeBps,
  int     exit
) {

  function transfer(signature claimSig, pubkey newClaimPk) {
    require(checkSig(claimSig, claimPk), "invalid claim sig");

    require(
      tx.outputs[0].scriptPubKey == new CappedSynth(
        newClaimPk, longPk, oraclePk, ticker, entryPrice,
        notionalFiat, totalCollateral, claimMargin, fundingRatePerSec,
        lastUpdate, exitFeeBps, exit
      ),
      "invalid transfer output"
    );
    require(tx.outputs[0].value >= totalCollateral, "collateral not preserved");
  }

  function addMargin(signature longSig, int amount) {
    require(checkSig(longSig, longPk), "invalid long-leg sig");
    require(amount > 0, "zero amount");

    int newTotalCollateral = totalCollateral + amount;

    require(
      tx.outputs[0].scriptPubKey == new CappedSynth(
        claimPk, longPk, oraclePk, ticker, entryPrice,
        notionalFiat, newTotalCollateral, claimMargin, fundingRatePerSec,
        lastUpdate, exitFeeBps, exit
      ),
      "invalid output"
    );
    require(tx.outputs[0].value >= newTotalCollateral, "margin not deposited");
  }

  function updateFunding(signature longSig, int newFundingRatePerSec) {
    require(checkSig(longSig, longPk), "invalid long-leg sig");
    require(newFundingRatePerSec >= 0, "negative funding rate disallowed");

    int elapsed           = tx.offchainTime - lastUpdate;
    require(elapsed >= 0, "clock regression");
    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;
    int delta             = notionalFiat * rateElapsedScaled / 1000000;
    int newNotionalFiat   = notionalFiat + delta;
    require(newNotionalFiat > 0, "notional wiped by funding");
    if (fundingRatePerSec != 0) {
      require(delta > 0, "no accrual; wait longer");
    }

    require(
      tx.outputs[0].scriptPubKey == new CappedSynth(
        claimPk, longPk, oraclePk, ticker, entryPrice,
        newNotionalFiat, totalCollateral, claimMargin, newFundingRatePerSec,
        tx.offchainTime, exitFeeBps, exit
      ),
      "invalid update output"
    );
    require(tx.outputs[0].value >= totalCollateral, "collateral not preserved");
  }

  function settle(
    signature claimSig,
    signature longSig,
    int       settlePrice
  ) {
    require(checkSig(claimSig, claimPk), "invalid claim sig");
    require(checkSig(longSig, longPk), "invalid long-leg sig");
    require(settlePrice > 0, "invalid settle price");

    int elapsed           = tx.offchainTime - lastUpdate;
    require(elapsed >= 0, "clock regression");
    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;
    int delta             = notionalFiat * rateElapsedScaled / 1000000;
    int newNotionalFiat   = notionalFiat + delta;
    require(newNotionalFiat > 0, "notional wiped by funding");

    int entrySats  = newNotionalFiat * 100000000 / entryPrice;
    int settleSats = newNotionalFiat * 100000000 / settlePrice;
    int gross      = claimMargin + settleSats - entrySats;

    if (gross <= 0) {
      require(tx.outputs[0].value >= totalCollateral, "long leg underpaid");
      require(tx.outputs[0].scriptPubKey == new SingleSig(longPk), "output 0 not long leg");
    } else {
      if (gross >= totalCollateral) {
        require(tx.outputs[0].value >= totalCollateral, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
      } else {
        require(tx.outputs[0].value >= gross, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
        int longPayout = totalCollateral - gross;
        if (longPayout > 330) {
          require(tx.outputs[1].value >= longPayout, "long leg underpaid");
          require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), "output 1 not long leg");
        }
      }
    }
  }

  function settleOracleClaim(
    signature claimSig,
    int       oraclePrice,
    int       oracleTime,
    signature oracleSig
  ) {
    require(checkSig(claimSig, claimPk), "invalid claim sig");
    require(oraclePrice > 0, "invalid oracle price");
    require(exitFeeBps >= 0, "invalid exit fee");

    int oracleAge = tx.offchainTime - oracleTime;
    require(oracleAge >= 0, "future-dated oracle");
    require(oracleAge <= 600, "stale oracle");

    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);
    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), "invalid oracle signature");

    int elapsed           = tx.offchainTime - lastUpdate;
    require(elapsed >= 0, "clock regression");
    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;
    int delta             = notionalFiat * rateElapsedScaled / 1000000;
    int newNotionalFiat   = notionalFiat + delta;
    require(newNotionalFiat > 0, "notional wiped by funding");

    int entrySats  = newNotionalFiat * 100000000 / entryPrice;
    int settleSats = newNotionalFiat * 100000000 / oraclePrice;
    int gross      = claimMargin + settleSats - entrySats;

    if (gross <= 0) {
      require(tx.outputs[0].value >= totalCollateral, "long leg underpaid");
      require(tx.outputs[0].scriptPubKey == new SingleSig(longPk), "output 0 not long leg");
    } else {
      if (gross >= totalCollateral) {
        int feeMax       = totalCollateral * exitFeeBps / 10000;
        int claimMaxNet  = totalCollateral - feeMax;
        require(tx.outputs[0].value >= claimMaxNet, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
        if (feeMax > 330) {
          require(tx.outputs[1].value >= feeMax, "long leg fee underpaid");
          require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), "output 1 not long leg");
        }
      } else {
        int fee        = gross * exitFeeBps / 10000;
        int claimNet   = gross - fee;
        int longPayout = totalCollateral - claimNet;
        require(tx.outputs[0].value >= claimNet, "claim underpaid");
        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), "output 0 not claim");
        if (longPayout > 330) {
          require(tx.outputs[1].value >= longPayout, "long leg underpaid");
          require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), "output 1 not long leg");
        }
      }
    }
  }
}
